{
 "level": "B1",
 "intro": "In this topic, you will learn in detail <strong>Past Continuous Passive</strong>: how to form this form, when to use it and how it differs from Past Simple Passive.",
 "rules": [
 {
 "label": "Formula",
 "color": "emerald",
 "text": "<strong>Subject + was/were + being + V3</strong>:",
 "example": "The house was being painted when I arrived."
 },
 {
 "label": "Denial",
 "color": "rose",
 "text": "<strong>Subject + was/were + not + being + V3</strong>:",
 "example": "The report was not being written at that time."
 },
 {
 "label": "Question",
 "color": "blue",
 "text": "<strong>Was/Were + Subject + being + V3?</strong>:",
 "example": "Was the project being developed?"
 }
 ]
}

{
 "title": "1. Structure of Past Continuous Passive",
 "intro": "The form of the verb <strong>be</strong> depends on the subject, and <strong>being</strong> remains unchanged:",
 "items": [
 {
 "label": "I/He/She/It",
 "title": "was being + V3",
 "subtitle": "The car was being repaired. - The car was being repaired."
 },
 {
 "label": "You/We/They",
 "title": "were being + V3",
 "subtitle": "The documents were being checked. - The documents were checked."
 },
 {
 "label": "Singular",
 "title": "was being + V3",
 "subtitle": "The house was being built. - The house was being built."
 },
 {
 "label": "Key",
 "title": "being is an unchanging part",
 "subtitle": "being always precedes V3."
 }
 ]
}

{
 "title": "2. Affirmative sentences",
 "sections": [
 {
 "label": "Structure",
 "color": "emerald",
 "description": "Word order: <strong>Subject + was/were + being + V3 (+ by agent)</strong>",
 "examples": [
 {
 "en": "The house was being painted when I arrived.",
 "ua": "The house was being painted when I arrived."
 },
 {
 "en": "The documents were being prepared all morning.",
 "ua": "The documents were being prepared all morning."
 },
 {
 "en": "The car was being repaired at 5 PM.",
 "ua": "The car was being repaired at 5 PM."
 },
 {
 "en": "The rooms were being cleaned by the staff.",
 "ua": "The rooms were being cleaned by the staff."
 }
 ]
 },
 {
 "label": "Continuous action in the past",
 "color": "sky",
 "description": "For actions that <strong>continued at a certain point in time</strong>:",
 "examples": [
 {
 "en": "At 3 PM, the meeting was being held.",
 "ua": "At 3 PM, the meeting was being held."
 },
 {
 "en": "The road was being repaired all day.",
 "ua": "The road was being repaired all day."
 },
 {
 "en": "The project was being discussed when he called.",
 "ua": "The project was being discussed when he called."
 }
 ]
 }
 ]
}

{
 "title": "3. When to use Past Continuous Passive?",
 "sections": [
 {
 "label": "Action in the past moment",
 "color": "emerald",
 "description": "For actions that were <strong>ongoing at some point in the past</strong>:",
 "examples": [
 {
 "en": "At 8 AM, breakfast was being served.",
 "ua": "At 8 AM, breakfast was being served."
 },
 {
 "en": "The building was being renovated last summer.",
 "ua": "The building was being renovated last summer."
 },
 {
 "en": "The reports were being prepared yesterday evening.",
 "ua": "The reports were being prepared yesterday evening."
 }
 ]
 },
 {
 "label": "Parallel actions",
 "color": "blue",
 "description": "When one action <strong>interrupted another ongoing</strong>:",
 "examples": [
 {
 "en": "The car was being washed when it started to rain.",
 "ua": "The car was being washed when it started to rain."
 },
 {
 "en": "The dinner was being cooked when the guests arrived.",
 "ua": "The dinner was being cooked when the guests arrived."
 },
 {
 "en": "The document was being printed when the power went out.",
 "ua": "The document was being printed when the power went out."
 }
 ]
 },
 {
 "label": "Duration of the process",
 "color": "amber",
 "description": "To emphasize the <strong>duration of the process</strong>:",
 "examples": [
 {
 "en": "The house was being built for two years.",
 "ua": "The house was being built for two years."
 },
 {
 "en": "The project was being developed throughout the year.",
 "ua": "The project was being developed throughout the year."
 },
 {
 "en": "The investigation was being conducted all week.",
 "ua": "The investigation was being conducted all week."
 }
 ]
 }
 ]
}

{
 "title": "4. Negative sentences",
 "sections": [
 {
 "label": "Structure",
 "color": "rose",
 "description": "Add <strong>not</strong> after was/were: <strong>Subject + was/were + not + being + V3</strong>",
 "examples": [
 {
 "en": "The report was not being written at that time.",
 "ua": "The report was not being written at that time."
 },
 {
 "en": "The rooms were not being cleaned yesterday.",
 "ua": "The rooms were not being cleaned yesterday."
 },
 {
 "en": "The problem was not being addressed.",
 "ua": "The problem was not being addressed."
 },
 {
 "en": "The orders were not being processed.",
 "ua": "The orders were not being processed."
 }
 ]
 },
 {
 "label": "Abbreviated forms",
 "color": "amber",
 "description": "Colloquially: <strong>wasn't being / weren't being</strong>",
 "examples": [
 {
 "en": "The car wasn't being repaired yesterday.",
 "ua": "The car wasn't being repaired yesterday."
 },
 {
 "en": "The packages weren't being delivered.",
 "ua": "The packages weren't being delivered."
 },
 {
 "en": "The issue wasn't being investigated.",
 "ua": "The issue wasn't being investigated."
 }
 ]
 }
 ]
}

{
 "title": "5. Interrogative sentences",
 "sections": [
 {
 "label": "Yes/No question",
 "color": "blue",
 "description": "<strong>Was/Were</strong> comes first: <strong>Was/Were + Subject + being + V3?</strong>",
 "examples": [
 {
 "en": "Was the house being painted?",
 "ua": "Was the house being painted?"
 },
 {
 "en": "Were the documents being checked?",
 "ua": "Were the documents being checked?"
 },
 {
 "en": "Was the project being developed?",
 "ua": "Was the project being developed?"
 },
 {
 "en": "Were they being interviewed?",
 "ua": "Were they being interviewed?"
 }
 ]
 },
 {
 "label": "Wh question",
 "color": "sky",
 "description": "<strong>Wh-word + was/were + Subject + being + V3?</strong>",
 "examples": [
 {
 "en": "What was being built there?",
 "ua": "What was being built there?"
 },
 {
 "en": "Why was the road being closed?",
 "ua": "Why was the road being closed?"
 },
 {
 "en": "Where were the tests being conducted?",
 "ua": "Where were the tests being conducted?"
 },
 {
 "en": "How was the problem being solved?",
 "ua": "How was the problem being solved?"
 }
 ]
 },
 {
 "label": "Short answers",
 "color": "amber",
 "description": "Answers with <strong>Yes/No + pronoun + was/were (not)</strong>:",
 "examples": [
 {
 "en": "Was the car being repaired? — Yes, it was. / No, it wasn't.",
 "ua": "Was the car being repaired? — Yes, it was. / No, it wasn't."
 },
 {
 "en": "Were they being interviewed? — Yes, they were. / No, they weren't.",
 "ua": "Were they being interviewed? — Yes, they were. / No, they weren't."
 }
 ]
 }
 ]
}

{
 "title": "6. Comparison of Active vs Passive in Past Continuous",
 "intro": "How to turn an active sentence into a passive:",
 "rows": [
 {
 "en": "Active: They were painting the house.",
 "ua": "Active: They were painting the house.",
 "note": "→ Passive: The house was being painted."
 },
 {
 "en": "Active: The manager was checking the documents.",
 "ua": "Active: The manager was checking the documents.",
 "note": "→ Passive: The documents were being checked."
 },
 {
 "en": "Active: Workers were repairing the road.",
 "ua": "Active: Workers were repairing the road.",
 "note": "→ Passive: The road was being repaired."
 },
 {
 "en": "Active: Someone was interviewing me.",
 "ua": "Active: Someone was interviewing me.",
 "note": "→ Passive: I was being interviewed."
 }
 ],
 "warning": "📌 Time markers (when, while, at that time) remain!"
}

{
 "title": "7. Past Simple Passive vs Past Continuous Passive",
 "intro": "Comparison of two forms — completed action vs continuous action:",
 "rows": [
 {
 "en": "The house was built in 1990.",
 "ua": "The house was built in 1990.",
 "note": "vs: The house was being built when I visited. — The house was under construction when I arrived."
 },
 {
 "en": "The car was repaired yesterday.",
 "ua": "The car was repaired yesterday.",
 "note": "vs: The car was being repaired at 5 PM. — The car was being repaired at 5:00 p.m."
 },
 {
 "en": "The report was written.",
 "ua": "The report was written.",
 "note": "vs: The report was being written all day. - The report was written all day."
 }
 ],
 "warning": "📌 Past Simple = fact, completed action. Past Continuous = process, continuous action."
}

{
 "title": "8. Time markers for Past Continuous Passive",
 "intro": "Typical words and expressions indicating the Past Continuous:",
 "items": [
 {
 "label": "Moment",
 "title": "at 5 PM, at that time, at noon",
 "subtitle": "The report was being written at 5 PM."
 },
 {
 "label": "Interrupt",
 "title": "when, while, as",
 "subtitle": "The house was being painted when it started to rain."
 },
 {
 "label": "Duration",
 "title": "all day, all morning, the whole week",
 "subtitle": "The road was being repaired all week."
 },
 {
 "label": "Parallelism",
 "title": "while, at the same time",
 "subtitle": "The dinner was being cooked while we waited."
 }
 ]
}

{
 "title": "9. Typical mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Skip being.",
 "wrong": "The house was painted when I arrived.",
 "right": "✅ The house was being painted when I arrived."
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Incorrect word order.",
 "wrong": "The report being was written.",
 "right": "✅ The report was being written."
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Using been instead of being.",
 "wrong": "The car was been repaired.",
 "right": "✅ The car was being repaired."
 },
 {
 "label": "Error 4",
 "color": "rose",
 "title": "Confusion of Past Simple and Continuous.",
 "wrong": "The house was being built in 1990.",
 "right": "✅ The house was built in 1990."
 }
 ]
}
